              className="mt-2 text-[12px]"
              style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#9ca3af" }}
            >
              {sourceCount !== undefined ? `${sourceCount} sources` : "-- sources"}
              {" \u00B7 "}
              {ctxCount !== undefined ? `${ctxCount} context sources` : "-- context sources"}
