                    (e.g. 1.1 &rarr; 1.2)
                  </span>
                </label>
                <label className="flex items-center gap-2.5 text-[13px]" style={{ color: "#374151" }}>
                  <input
                    type="checkbox"
                    checked={currentRules.on_security_patch ?? false}
