                  Security patch
                  <span className="text-[11px]" style={{ color: "#9ca3af" }}>
                    (contains security/CVE keywords)
                  </span>
                </label>
                <div className="pt-2">
                  <label className="mb-1.5 block text-[13px]" style={{ color: "#374151" }}>
                    Version pattern
