        >
          <h2
            style={{
              fontFamily: "var(--font-fraunces)",
              fontSize: "16px",
              fontWeight: 600,
              color: "#111113",
            }}
          >
            Release Notes
          </h2>
        </div>
        <div className="px-5 py-4">
