        </p>
      )}

      {/* 5. Meta line */}
      <div
        className="mt-3 flex items-center gap-2 text-[13px] text-[#6b7280]"
        style={{ fontFamily: "var(--font-dm-sans)" }}
      >
        <StatusDot status={sr.status} />
        <span className="flex-1">
          {sr.status}
